EXISTS (`ClassInstanceExpr CIE`, `RefType T`) {
  AND {
    (`the type of CIE is T`),
    (`T has an ancestor type with qualified name "java.io.Writer" or "java.io.OutputStream"`),
    (NOT {
      EXISTS (`RefType DERIVED_TYPE`) {
        AND {
          (OR {
            (`DERIVED_TYPE is the type of CIE`),
            (EXISTS (`Expr TRANSPARENT`) {
              (`there is a transitive closeable-init flow from CIE to TRANSPARENT`)
            })
          }),
          (`DERIVED_TYPE has an ancestor type with qualified name "java.io.CharArrayWriter", "java.io.StringWriter", or "java.io.ByteArrayOutputStream"`)
        }
      }
    }),
    (NOT {
      EXISTS (`CloseableInitExpr INNER`) {
        AND {
          (`there is a transitive closeable-init flow from CIE to INNER`),
          (OR {
            (AND {
              (`INNER is locally initialized`),
              (OR {
                (AND {
                  (`INNER is a ClassInstanceExpr`),
                  (NOT { (`INNER has at least one constructor argument`) })
                }),
                (EXISTS (`RefType T0`) {
                  AND {
                    (`T0 is the type of INNER`),
                    (EXISTS (`Method CLOSE_METHOD`) {
                      AND {
                        (`CLOSE_METHOD is declared in T0`),
                        (`the name of CLOSE_METHOD is "close"`),
                        (NOT { (`CLOSE_METHOD has a body with at least one child`) })
                      }
                    })
                  }
                }),
                (EXISTS (`CloseableInitExpr SQL_STMT`, `LocalVariableDecl V`) {
                  AND {
                    (`the type of SQL_STMT has an ancestor that is a SQL Statement type`),
                    (`SQL_STMT flows into V`),
                    (`the type of INNER is a SQL ResultSet type`),
                    (`INNER is a SqlResourceOpeningMethodCall`),
                    (`the qualifier of INNER is an access of V`)
                  }
                }),
                (EXISTS (`MethodCall MA`) {
                  AND {
                    (`INNER is a ClassInstanceExpr`),
                    (`MA is an argument to the constructor of INNER`),
                    (OR {
                      (`MA's method is a ServletResponseGetOutputStreamMethod`),
                      (`MA's method is a ServletResponseGetWriterMethod`),
                      (`MA's method is a ServletRequestGetBodyMethod`)
                    })
                  }
                })
              })
            }),
            (EXISTS (`CloseableInitExpr INNER2`) {
              (`there is a transitive closeable-init flow from INNER to INNER2`)
            }),
            (EXISTS (`CloseableInitExpr INNER3`) {
              (`there is a transitive closeable-init flow from INNER to INNER3`)
            })
          })
        }
      }
    }),
    (EXISTS (`CloseableInitExpr CIE_AS_CLOSEABLE`) {
      AND {
        (`CIE_AS_CLOSEABLE = CIE`),
        (NOT {
          EXISTS (`CloseableInitExpr CIE2`) {
            AND {
              (`CIE2 != CIE_AS_CLOSEABLE`),
              (`there is a transitive closeable-init flow from CIE_AS_CLOSEABLE to CIE2`)
            }
          }
        })
      }
    })
  }
}
